#!/usr/bin/env python3
"""
Service Discovery - Enables frontend to discover backend port and vice versa.

Generates .env.ports file that can be sourced by both services.
"""

import argparse
import json
import sys
from datetime import datetime, timezone
from pathlib import Path
from typing import Optional

# Add scripts directory to path for imports
sys.path.insert(0, str(Path(__file__).parent))

from port.port_manager import PortManager


class ServiceDiscovery:
    """Manages service discovery between frontend and backend."""

    ENV_PORTS_FILE = ".env.ports"
    BACKEND_SERVICE_NAME = "ai-real-estate-assistant"
    FRONTEND_SERVICE_NAME = "ai-real-estate-assistant-web"

    def __init__(self, project_root: Path):
        self.project_root = project_root
        self._port_manager: Optional[PortManager] = None

    @property
    def port_manager(self) -> PortManager:
        """Lazy load port manager."""
        if self._port_manager is None:
            self._port_manager = PortManager(self.project_root)
        return self._port_manager

    def generate_env_ports_file(
        self,
        backend_port: int,
        frontend_port: int,
        *,
        extra_vars: Optional[dict[str, str]] = None,
    ) -> Path:
        """Generate .env.ports file with port configuration."""
        content = f"""# Auto-generated port configuration
# Generated by service-discovery.py at {datetime.now(timezone.utc).isoformat()}
# DO NOT EDIT MANUALLY - changes will be overwritten

# Backend Configuration
BACKEND_PORT={backend_port}
BACKEND_URL=http://localhost:{backend_port}
BACKEND_API_URL=http://localhost:{backend_port}/api/v1

# Frontend Configuration
FRONTEND_PORT={frontend_port}
FRONTEND_URL=http://localhost:{frontend_port}

# CORS Configuration (for backend)
CORS_ALLOW_ORIGINS=http://localhost:{frontend_port}

# Next.js Environment Variables
NEXT_PUBLIC_API_URL=/api/v1
"""

        # Add extra variables if provided
        if extra_vars:
            content += "\n# Additional Configuration\n"
            for key, value in sorted(extra_vars.items()):
                content += f"{key}={value}\n"

        env_path = self.project_root / self.ENV_PORTS_FILE
        env_path.write_text(content, encoding="utf-8")
        return env_path

    def load_ports_from_registry(self) -> dict[str, int]:
        """Load port allocations from registry."""
        return self.port_manager.get_all_allocated_ports()

    def ensure_ports_configured(
        self,
        *,
        preferred_backend: Optional[int] = None,
        preferred_frontend: Optional[int] = None,
    ) -> tuple[int, int]:
        """
        Ensure ports are allocated and return (backend_port, frontend_port).

        If ports are already allocated in the registry, returns those.
        Otherwise, allocates new ports.
        """
        pm = self.port_manager

        # Check existing allocations
        backend_alloc = pm.get_allocation(self.BACKEND_SERVICE_NAME)
        frontend_alloc = pm.get_allocation(self.FRONTEND_SERVICE_NAME)

        if backend_alloc and frontend_alloc:
            backend_port = backend_alloc["port"]
            frontend_port = frontend_alloc["port"]
            print(
                f"Using existing allocations: backend={backend_port}, frontend={frontend_port}"
            )
        else:
            # Allocate new ports
            backend_port = pm.allocate_port(
                "backend", self.BACKEND_SERVICE_NAME, preferred=preferred_backend
            )
            frontend_port = pm.allocate_port(
                "frontend", self.FRONTEND_SERVICE_NAME, preferred=preferred_frontend
            )
            print(
                f"Allocated new ports: backend={backend_port}, frontend={frontend_port}"
            )

        # Generate .env.ports
        self.generate_env_ports_file(backend_port, frontend_port)

        return backend_port, frontend_port

    def get_backend_url(self) -> str:
        """Get backend URL for frontend to use."""
        ports = self.load_ports_from_registry()
        backend_port = ports.get("backend", 8000)
        return f"http://localhost:{backend_port}/api/v1"

    def get_frontend_url(self) -> str:
        """Get frontend URL for backend CORS."""
        ports = self.load_ports_from_registry()
        frontend_port = ports.get("frontend", 3800)
        return f"http://localhost:{frontend_port}"

    def get_ports(self) -> dict[str, int]:
        """Get all port allocations as a dict."""
        return self.load_ports_from_registry()

    def release_all(self) -> None:
        """Release all port allocations for this project."""
        pm = self.port_manager

        backend_alloc = pm.get_allocation(self.BACKEND_SERVICE_NAME)
        frontend_alloc = pm.get_allocation(self.FRONTEND_SERVICE_NAME)

        if backend_alloc:
            pm.release_port(backend_alloc["port"])
            print(f"Released backend port {backend_alloc['port']}")

        if frontend_alloc:
            pm.release_port(frontend_alloc["port"])
            print(f"Released frontend port {frontend_alloc['port']}")


def main(argv: list[str] | None = None) -> int:
    parser = argparse.ArgumentParser(
        description="Service discovery for AI Real Estate Assistant"
    )
    parser.add_argument("--project-root", type=Path, help="Project root directory")
    parser.add_argument(
        "--allocate",
        action="store_true",
        help="Allocate ports if not already allocated",
    )
    parser.add_argument("--preferred-backend", type=int, help="Preferred backend port")
    parser.add_argument(
        "--preferred-frontend", type=int, help="Preferred frontend port"
    )
    parser.add_argument(
        "--release", action="store_true", help="Release all port allocations"
    )
    parser.add_argument("--json", action="store_true", help="Output as JSON")
    parser.add_argument(
        "--get-backend-url", action="store_true", help="Print backend URL"
    )
    parser.add_argument(
        "--get-frontend-url", action="store_true", help="Print frontend URL"
    )
    args = parser.parse_args(argv)

    # Determine project root
    if args.project_root:
        project_root = args.project_root
    else:
        project_root = Path(__file__).resolve().parents[1]

    sd = ServiceDiscovery(project_root)

    if args.release:
        sd.release_all()
        return 0

    if args.get_backend_url:
        print(sd.get_backend_url())
        return 0

    if args.get_frontend_url:
        print(sd.get_frontend_url())
        return 0

    if args.allocate:
        backend_port, frontend_port = sd.ensure_ports_configured(
            preferred_backend=args.preferred_backend,
            preferred_frontend=args.preferred_frontend,
        )

        if args.json:
            result = {
                "backend_port": backend_port,
                "frontend_port": frontend_port,
                "backend_url": f"http://localhost:{backend_port}",
                "frontend_url": f"http://localhost:{frontend_port}",
                "backend_api_url": f"http://localhost:{backend_port}/api/v1",
                "cors_allow_origins": f"http://localhost:{frontend_port}",
                "env_file": str(project_root / sd.ENV_PORTS_FILE),
            }
            print(json.dumps(result, indent=2))
        else:
            print(f"BACKEND_PORT={backend_port}")
            print(f"FRONTEND_PORT={frontend_port}")
            print(f"BACKEND_URL=http://localhost:{backend_port}")
            print(f"FRONTEND_URL=http://localhost:{frontend_port}")
        return 0

    # Default: show current status
    ports = sd.get_ports()
    if args.json:
        print(json.dumps(ports, indent=2))
    else:
        for category, port in sorted(ports.items()):
            print(f"{category.upper()}_PORT={port}")

    return 0


if __name__ == "__main__":
    sys.exit(main(sys.argv[1:]))
